parameters.jsCode:
const body = $input.item.json.body || $input.item.json;

const roleLabels = {
  'real-estate-solo': 'Solo Real Estate Agent',
  'real-estate-team': 'Team Lead / Broker',
  'med-spa':          'Med Spa / Aesthetic Clinic',
  'legal':            'Legal / Law Firm',
  'contractor':       'Contractor / Home Services',
  'insurance':        'Insurance Agent',
  'other':            'Other'
};

const role = body.role || body.industry || '';
const industryLabel = roleLabels[role] || role || 'Not specified';

const name   = (body.name  || '').trim();
const email  = (body.email || '').trim();
const phone  = (body.phone || '').trim().replace(/[^\d+]/g, '') || null;
const source = body.source || 'website_form';

let normalizedPhone = phone;
if (phone && !phone.startsWith('+')) {
  const digits = phone.replace(/\D/g, '');
  normalizedPhone = digits.length === 10 ? '+1' + digits : '+' + digits;
}

const firstName = name.split(' ')[0] || name;

return [{ json: {
  name,
  firstName,
  email,
  phone:           normalizedPhone,
  industry:        industryLabel,
  industryKey:     role,
  source,
  leadStatus:      'new',
  serviceInterest: 'AI receptionist consultation',
  createdAt:       new Date().toISOString()
} }];

