const lead = $('Extract Lead Data').item.json;
const gptRaw = $input.item.json;

let urgency = 'warm';
let outreach = '';
let reason = '';

try {
  const content = gptRaw.choices?.[0]?.message?.content || '{}';
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  urgency  = ['hot','warm','cold'].includes(parsed.urgency) ? parsed.urgency : 'warm';
  outreach = parsed.outreach || '';
  reason   = parsed.reason   || '';
} catch(e) {
  console.log('GPT parse error, defaulting to warm:', e.message);
}

return [{ json: {
  ...lead,
  urgency,
  outreach,
  reason
} }];

// Pull data from Parse GPT Score (ancestor node — always in scope)
const lead = $('Parse GPT Score').item.json;
const urgency = lead.urgency || '';
const phone   = lead.phone   || '';
const name    = lead.name    || '';

// Only pass through if hot AND has a phone number
if (urgency === 'hot' && phone) {
  return [{ json: { urgency, phone, name } }];
}

// Return empty — stops execution, no call placed
return [];
